              "forbidden trailer");
    }

    const char * const x =
      http_request_field_check_value(tpctx->v, tpctx->vlen,
                                     tpctx->http_header_strict);
    if (x)
        return http_request_header_char_invalid(r, *x,
          "invalid character in trailer");

    return 0;
}

